#[tokio::main]
async fn main() {
    if let Err(error) = run().await {
        eprintln!("{error}");
        std::process::exit(1);
    }
}

async fn run() -> Result<(), String> {
    let args = env::args_os().skip(1).collect::<Vec<_>>();
    if let Some(once) = parse_serve_args(&args)? {
        return serve(once).await;
    }

    cli::run_from_args(args).await
}

fn parse_serve_args(args: &[OsString]) -> Result<Option<bool>, String> {
    if args.first().is_none_or(|arg| arg != "serve") {
        return Ok(None);
    }

    match args {
        [_] => Ok(Some(false)),
        [_, flag] if flag == "--once" => Ok(Some(true)),
        _ => Err("usage: slskr serve [--once]".to_owned()),
    }
}

#[derive(Clone, Debug)]
struct ShareRoot {
    label: String,
    files: usize,
    bytes: u64,
    extensions: Vec<ShareExtensionSummary>,
}

#[derive(Clone, Debug)]
struct ShareExtensionSummary {
    extension: String,
    files: usize,
    bytes: u64,
}

impl ShareExtensionSummary {
    fn json(&self) -> String {
        format!(
            "{{\"extension\":\"{}\",\"files\":{},\"bytes\":{}}}",
            json_escape(&self.extension),
            self.files,
            self.bytes
        )
    }
}

impl ShareRoot {
    fn json(&self) -> String {
        let extensions = self
            .extensions
            .iter()
            .map(ShareExtensionSummary::json)
            .collect::<Vec<_>>()
            .join(",");
        format!(
            "{{\"label\":\"{}\",\"files\":{},\"bytes\":{},\"extensions\":[{}]}}",
            json_escape(&self.label),
            self.files,
            self.bytes,
            extensions
        )
    }
}

