fn extract_json_u32_field(body: &str, field: &str) -> Option<u32> {
    serde_json::from_str::<serde_json::Value>(body)
        .ok()?
        .get(field)?
        .as_u64()
        .and_then(|value| u32::try_from(value).ok())
}

fn extract_json_bool_field(body: &str, field: &str) -> Option<bool> {
    serde_json::from_str::<serde_json::Value>(body)
        .ok()?
        .get(field)?
        .as_bool()
}

fn extract_json_u64_field(body: &str, field: &str) -> Option<u64> {
    serde_json::from_str::<serde_json::Value>(body)
        .ok()?
        .get(field)?
        .as_u64()
}

fn extract_json_optional_u64_field(body: &str, field: &str) -> Option<Option<u64>> {
    let value = serde_json::from_str::<serde_json::Value>(body).ok()?;
    let value = value.get(field)?;
    if value.is_null() {
        Some(None)
    } else {
        value.as_u64().map(Some)
    }
}

fn extract_json_i32_field(body: &str, field: &str) -> Option<i32> {
    serde_json::from_str::<serde_json::Value>(body)
        .ok()?
        .get(field)?
        .as_i64()
        .and_then(|value| i32::try_from(value).ok())
}

fn rate_limit_user_key(authenticated_token: &str) -> String {
    use sha2::{Digest, Sha256};

    let digest = Sha256::digest(authenticated_token.as_bytes());
    format!("auth:{}", hex::encode(&digest[..16]))
}

fn authenticated_rate_limit_user_key(
    config: &AppConfig,
    authorization: Option<&str>,
    cookie: Option<&str>,
) -> Option<String> {
    is_authorized(config, authorization, cookie)
        .then_some(config.api_token.as_deref())
        .flatten()
        .map(rate_limit_user_key)
}

fn rate_limit_remote_addr(
    config: &AppConfig,
    remote_addr: Option<SocketAddr>,
    headers: &http_server::HttpHeaders,
) -> Option<SocketAddr> {
    let remote_addr = remote_addr?;
    if !config
        .trusted_proxy_cidrs
        .iter()
        .any(|cidr| cidr.contains(remote_addr.ip()))
    {
        return Some(remote_addr);
    }

    forwarded_client_ip(config, remote_addr.ip(), headers)
        .map(|ip| SocketAddr::new(ip, 0))
        .or(Some(remote_addr))
}

fn forwarded_client_ip(
    config: &AppConfig,
    remote_ip: IpAddr,
    headers: &http_server::HttpHeaders,
) -> Option<IpAddr> {
    let forwarded_ips = if let Some(value) = headers.forwarded.as_deref() {
        forwarded_header_client_ips(value)?
    } else {
        let value = headers.x_forwarded_for.as_deref()?;
        x_forwarded_for_client_ips(value)?
    };

    forwarded_ips
        .into_iter()
        .chain(std::iter::once(remote_ip))
        .rev()
        .find(|ip| {
            !config
                .trusted_proxy_cidrs
                .iter()
                .any(|cidr| cidr.contains(*ip))
        })
}

fn x_forwarded_for_client_ips(value: &str) -> Option<Vec<IpAddr>> {
    let ips = value
        .split(',')
        .map(parse_forwarded_ip_token)
        .collect::<Option<Vec<_>>>()?;
    (!ips.is_empty()).then_some(ips)
}

fn forwarded_header_client_ips(value: &str) -> Option<Vec<IpAddr>> {
    let ips = value
        .split(',')
        .map(parse_forwarded_element_ip)
        .collect::<Option<Vec<_>>>()?;
    (!ips.is_empty()).then_some(ips)
}

fn parse_forwarded_element_ip(entry: &str) -> Option<IpAddr> {
    let mut forwarded_ip = None;
    for part in entry.split(';') {
        let (name, value) = part.trim().split_once('=')?;
        if !name.trim().eq_ignore_ascii_case("for") {
            continue;
        }
        if forwarded_ip.is_some() {
            return None;
        }
        forwarded_ip = Some(parse_forwarded_ip_token(value)?);
    }
    forwarded_ip
}

fn parse_forwarded_ip_token(value: &str) -> Option<IpAddr> {
    let value = value.trim();
    let value = match (value.strip_prefix('"'), value.strip_suffix('"')) {
        (Some(without_prefix), Some(_)) => without_prefix.strip_suffix('"')?,
        (None, None) => value,
        _ => return None,
    };
    if value.is_empty() || value.contains(['"', '\\']) {
        return None;
    }
    if value.eq_ignore_ascii_case("unknown") || value.starts_with('_') {
        return None;
    }
    if let Some(bracketed) = value.strip_prefix('[') {
        let (host, suffix) = bracketed.split_once(']')?;
        if !suffix.is_empty()
            && suffix
                .strip_prefix(':')
                .and_then(|port| port.parse::<u16>().ok())
                .is_none()
        {
            return None;
        }
        return host.parse::<std::net::Ipv6Addr>().ok().map(IpAddr::V6);
    }
    if value.contains(['[', ']']) {
        return None;
    }
    if let Ok(ip) = value.parse::<IpAddr>() {
        return Some(ip);
    }
    let (host, port) = value.rsplit_once(':')?;
    port.parse::<u16>().ok()?;
    host.parse::<std::net::Ipv4Addr>().ok().map(IpAddr::V4)
}

fn websocket_auth_protocol(protocol_header: Option<&str>) -> Option<&str> {
    protocol_header?
        .split(',')
        .map(str::trim)
        .find(|protocol| decode_websocket_auth_protocol(protocol).is_some())
}

fn websocket_auth_protocol_count(protocol_header: Option<&str>) -> usize {
    protocol_header
        .into_iter()
        .flat_map(|header| header.split(','))
        .map(str::trim)
        .filter(|protocol| decode_websocket_auth_protocol(protocol).is_some())
        .take(2)
        .count()
}

fn websocket_protocol_authorization(protocol_header: Option<&str>) -> Option<String> {
    let protocol = websocket_auth_protocol(protocol_header)?;
    let token = decode_websocket_auth_protocol(protocol)?;
    Some(format!("Bearer {token}"))
}

fn mixed_websocket_auth_credentials(
    headers: &http_server::HttpHeaders,
    websocket_authorization: Option<&str>,
) -> bool {
    websocket_auth_protocol_count(headers.sec_websocket_protocol.as_deref()) > 1
        || (websocket_authorization.is_some()
            && (headers.authorization.is_some() || headers.x_api_key.is_some()))
}

fn decode_websocket_auth_protocol(protocol: &str) -> Option<String> {
    if !is_websocket_protocol_token(protocol) {
        return None;
    }
    let encoded = protocol.strip_prefix(WEBSOCKET_AUTH_PROTOCOL_PREFIX)?;
    let token = strict_percent_decode(encoded)?;
    (!token.is_empty()
        && !token
            .chars()
            .any(|character| character.is_control() || character == '\u{7f}'))
    .then_some(token)
}

fn strict_percent_decode(value: &str) -> Option<String> {
    let bytes = value.as_bytes();
    let mut decoded = Vec::with_capacity(bytes.len());
    let mut index = 0;
    while index < bytes.len() {
        if bytes[index] == b'%' {
            let high = strict_hex_value(*bytes.get(index + 1)?)?;
            let low = strict_hex_value(*bytes.get(index + 2)?)?;
            decoded.push((high << 4) | low);
            index += 3;
        } else {
            decoded.push(bytes[index]);
            index += 1;
        }
    }
    String::from_utf8(decoded).ok()
}

fn strict_hex_value(value: u8) -> Option<u8> {
    match value {
        b'0'..=b'9' => Some(value - b'0'),
        b'a'..=b'f' => Some(value - b'a' + 10),
        b'A'..=b'F' => Some(value - b'A' + 10),
        _ => None,
    }
}

fn is_websocket_protocol_token(value: &str) -> bool {
    !value.is_empty()
        && value.bytes().all(|byte| {
            byte.is_ascii_alphanumeric()
                || matches!(
                    byte,
                    b'!' | b'#'
                        | b'$'
                        | b'%'
                        | b'&'
                        | b'\''
                        | b'*'
                        | b'+'
                        | b'-'
                        | b'.'
                        | b'^'
                        | b'_'
                        | b'`'
                        | b'|'
                        | b'~'
                )
        })
}

fn slskd_transfer_user_path<'a>(path: &'a str, direction: &str) -> Option<&'a str> {
    let prefix = format!("/api/transfers/{direction}/");
    path.strip_prefix(&prefix)
        .filter(|username| !username.is_empty() && !username.contains('/'))
}

fn slskd_transfer_file_path<'a>(path: &'a str, direction: &str) -> Option<(&'a str, u64)> {
    let prefix = format!("/api/transfers/{direction}/");
    let rest = path.strip_prefix(&prefix)?;
    let (username, tail) = rest.split_once('/')?;
    let id = tail.split_once('/').map_or(
        tail,
        |(id, suffix)| {
            if suffix == "position" {
                id
            } else {
                ""
            }
        },
    );
    if username.is_empty() || username.contains('/') || id.is_empty() {
        return None;
    }
    Some((username, id.parse().ok()?))
}

fn slskd_transfer_position_path(path: &str) -> Option<(&str, u64)> {
    slskd_transfer_file_path(path, "downloads").filter(|_| path.ends_with("/position"))
}

fn transfer_resource_segment(path: &str) -> Option<&str> {
    path_segment_after(path, "/api/transfers/")
        .or_else(|| path_segment_after(path, "/api/v0/transfers/"))
}

fn slskd_file_storage_resource_path(path: &str) -> Option<(&str, &str, &str)> {
    let mut segments = path.strip_prefix("/api/files/")?.split('/');
    let storage = segments.next()?;
    let resource = segments.next()?;
    let encoded_name = segments.next()?;
    if segments.next().is_some()
        || !matches!(storage, "downloads" | "incomplete")
        || !matches!(resource, "directories" | "files")
        || encoded_name.is_empty()
    {
        return None;
    }
    Some((storage, resource, encoded_name))
}

fn file_storage_error_response(error: &str) -> HttpResponse {
    if matches!(
        error,
        STORAGE_DIRECTORY_ENTRY_LIMIT_ERROR
            | STORAGE_DIRECTORY_DELETE_ENTRY_LIMIT_ERROR
            | STORAGE_DIRECTORY_DELETE_TOTAL_LIMIT_ERROR
            | STORAGE_DIRECTORY_DELETE_DEPTH_ERROR
    ) {
        HttpResponse {
            status: "413 Payload Too Large",
            content_type: "application/json",
            body: if error == STORAGE_DIRECTORY_ENTRY_LIMIT_ERROR {
                "{\"error\":\"storage directory is too large to list\"}".to_owned()
            } else if matches!(
                error,
                STORAGE_DIRECTORY_DELETE_ENTRY_LIMIT_ERROR
                    | STORAGE_DIRECTORY_DELETE_TOTAL_LIMIT_ERROR
            ) {
                "{\"error\":\"storage directory is too large to delete\"}".to_owned()
            } else {
                "{\"error\":\"storage directory tree is too deep to delete\"}".to_owned()
            },
        }
    } else if error.contains("failed:") {
        eprintln!("file storage operation failed: {error}");
        routing::service_unavailable_response("file storage unavailable")
    } else {
        routing::bad_request_response(error)
    }
}

fn slskd_files_from_body(body: &str) -> Vec<serde_json::Value> {
    let Ok(payload) = serde_json::from_str::<serde_json::Value>(body) else {
        return Vec::new();
    };
    if let Some(files) = payload.get("files").and_then(serde_json::Value::as_array) {
        return files.clone();
    }
    if payload.get("filename").is_some() {
        return vec![payload];
    }
    payload.as_array().cloned().unwrap_or_default()
}

fn slskd_transfer_batch_id(body: &str) -> Option<String> {
    let payload = serde_json::from_str::<serde_json::Value>(body).ok()?;
    ["batchId", "batch_id", "id"]
        .iter()
        .find_map(|field| payload.get(field).and_then(serde_json::Value::as_str))
        .map(str::trim)
        .filter(|value| !value.is_empty() && uuid::Uuid::parse_str(value).is_ok())
        .map(str::to_owned)
}

fn transfer_request_details_from_json(
    value: &serde_json::Value,
    filename: &str,
) -> TransferRequestDetails {
    let text = |names: &[&str], max_bytes: usize| {
        names
            .iter()
            .find_map(|name| value.get(name).and_then(serde_json::Value::as_str))
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(|value| truncate_utf8_bytes(value.to_owned(), max_bytes))
    };
    let number = |names: &[&str]| {
        names
            .iter()
            .find_map(|name| value.get(name).and_then(serde_json::Value::as_u64))
            .and_then(|value| u32::try_from(value).ok())
    };
    let request_id = text(&["requestId", "request_id"], MAX_TRANSFER_REQUEST_ID_BYTES)
        .filter(|value| uuid::Uuid::parse_str(value).is_ok())
        .or_else(|| Some(uuid::Uuid::new_v4().to_string()));
    TransferRequestDetails {
        request_id,
        request_name: text(
            &["requestName", "request_name", "name"],
            MAX_TRANSFER_REQUEST_NAME_BYTES,
        )
        .or_else(|| Some(virtual_basename(filename).to_owned())),
        destination_directory: text(
            &[
                "destinationDirectory",
                "destination_directory",
                "destination",
            ],
            MAX_TRANSFER_LOCAL_PATH_BYTES,
        ),
        bit_rate: number(&["bitRate", "bit_rate", "bitrate"]),
        sample_rate: number(&["sampleRate", "sample_rate", "samplerate"]),
        bit_depth: number(&["bitDepth", "bit_depth", "bitdepth"]),
        length_seconds: number(&["length", "lengthSeconds", "length_seconds"]),
        artist: text(&["artist"], MAX_TRANSFER_METADATA_TEXT_BYTES),
        album: text(&["album"], MAX_TRANSFER_METADATA_TEXT_BYTES),
        title: text(&["title"], MAX_TRANSFER_METADATA_TEXT_BYTES),
        track_number: number(&["trackNumber", "track_number"]),
        year: number(&["year"]),
    }
}

fn slskd_enqueue_request(body: &str) -> Option<(String, Vec<serde_json::Value>)> {
    let payload = serde_json::from_str::<serde_json::Value>(body).ok()?;
    let username = payload.get("username")?.as_str()?.to_owned();
    let files = payload
        .get("files")
        .and_then(serde_json::Value::as_array)
        .cloned()
        .unwrap_or_default();
    (!files.is_empty()).then_some((username, files))
}

fn json_body_string(body: &str) -> Option<String> {
    serde_json::from_str::<serde_json::Value>(body)
        .ok()
        .and_then(|value| value.as_str().map(str::to_owned))
}

fn path_segment_after<'a>(path: &'a str, prefix: &str) -> Option<&'a str> {
    path.strip_prefix(prefix)
        .filter(|segment| !segment.is_empty() && !segment.contains('/'))
}

fn download_request_path(path: &str) -> Option<(&str, Option<&str>)> {
    let rest = path
        .strip_prefix("/api/v0/downloads/requests/")
        .or_else(|| path.strip_prefix("/api/downloads/requests/"))?;
    let (id, action) = rest
        .split_once('/')
        .map_or((rest, None), |(id, action)| (id, Some(action)));
    (!id.is_empty()
        && !id.contains('/')
        && uuid::Uuid::parse_str(id).is_ok()
        && action.is_none_or(|action| !action.is_empty() && !action.contains('/')))
    .then_some((id, action))
}

fn path_segment_between<'a>(path: &'a str, prefix: &str, suffix: &str) -> Option<&'a str> {
    let segment = path.strip_prefix(prefix)?.strip_suffix(suffix)?;
    (!segment.is_empty() && !segment.contains('/')).then_some(segment)
}

fn decoded_path_segment(segment: &str) -> String {
    percent_decode_component(segment)
}

async fn create_preview_stream_ticket(
    state: &AppState,
    family: &str,
    body: &str,
) -> Result<String, String> {
    let content_id = extract_json_string_field(body, "contentId")
        .or_else(|| extract_json_string_field(body, "content_id"))
        .or_else(|| extract_json_string_field(body, "id"));
    let filename = extract_json_string_field(body, "filename")
        .or_else(|| extract_json_string_field(body, "path"))
        .or_else(|| content_id.clone())
        .ok_or_else(|| "filename/contentId is required".to_owned())?;
    let peer_username = extract_json_string_field(body, "username")
        .or_else(|| extract_json_string_field(body, "peerUsername"))
        .or_else(|| extract_json_string_field(body, "peer_username"))
        .or_else(|| extract_json_string_field(body, "peerId"));
    let requested_size = extract_json_u64_field(body, "size").unwrap_or(0);
    if requested_size > MAX_PREVIEW_STREAM_BYTES {
        return Err("preview stream size exceeds the 2 GiB limit".to_owned());
    }
    let source_url = extract_json_string_field(body, "sourceUrl")
        .or_else(|| extract_json_string_field(body, "source_url"));
    let source_authorization = extract_json_string_field(body, "sourceAuthorization")
        .or_else(|| extract_json_string_field(body, "source_authorization"));
    let expected_hash = extract_json_string_field(body, "expectedHash")
        .or_else(|| extract_json_string_field(body, "expected_hash"));
    if peer_username.as_deref().is_none_or(str::is_empty) {
        return Err(if family == "mesh" {
            "peerId is required".to_owned()
        } else {
            "username is required".to_owned()
        });
    }
    if family == "mesh" && content_id.as_deref().is_none_or(str::is_empty) {
        return Err("contentId is required".to_owned());
    }
    let content_type = preview_stream_content_type(&filename);
    if content_type == "application/octet-stream" {
        return Err("only audio files can be preview streamed".to_owned());
    }
    let content_type = content_type.to_owned();
    let remote_mesh = match source_url {
        Some(_) if family != "mesh" => {
            return Err("sourceUrl is supported only for mesh preview streams".to_owned());
        }
        Some(source_url) => {
            if requested_size == 0 {
                return Err("size is required for a remote mesh preview".to_owned());
            }
            if source_authorization
                .as_ref()
                .is_some_and(|value| value.contains(['\r', '\n']) || value.len() > 8 * 1024)
            {
                return Err("sourceAuthorization is invalid".to_owned());
            }
            let expected_hash = expected_hash
                .as_deref()
                .map(str::trim)
                .filter(|hash| {
                    hash.len() == 64 && hash.bytes().all(|byte| byte.is_ascii_hexdigit())
                })
                .ok_or_else(|| {
                    "expectedHash must be a SHA-256 digest for a remote mesh preview".to_owned()
                })?
                .to_ascii_lowercase();
            Some((source_url, source_authorization, expected_hash))
        }
        None => None,
    };

    let shares = state.shares.read().await;
    let transfers = state.transfers.read().await;
    let searches = state.searches.read().await;
    let share = shares.entries.iter().find(|entry| {
        let hash = stable_content_hash(&entry.filename, entry.size).to_string();
        entry.filename == filename
            || content_id.as_deref() == Some(entry.filename.as_str())
            || content_id.as_deref() == Some(hash.as_str())
    });
    let transfer = transfers.entries.iter().find(|entry| {
        entry.filename == filename
            || content_id
                .as_deref()
                .and_then(|id| id.strip_prefix("transfer-"))
                .and_then(|id| id.parse::<u64>().ok())
                == Some(entry.id)
    });
    let search_result = searches.records.iter().find_map(|record| {
        record.results.iter().find(|result| {
            (result.filename == filename || content_id.as_deref() == Some(result.filename.as_str()))
                && peer_username
                    .as_deref()
                    .is_none_or(|peer| result.peer_username.as_deref() == Some(peer))
        })
    });

    let resolved_filename = share
        .map(|entry| entry.filename.clone())
        .or_else(|| transfer.map(|entry| entry.filename.clone()))
        .or_else(|| search_result.map(|entry| entry.filename.clone()))
        .unwrap_or(filename);
    let resolved_size = share
        .map(|entry| entry.size)
        .or_else(|| transfer.and_then(|entry| entry.size))
        .or_else(|| search_result.map(|entry| entry.size))
        .unwrap_or(requested_size);
    let resolved_content_id = content_id
        .unwrap_or_else(|| stable_content_hash(&resolved_filename, resolved_size).to_string());
    let resolved_peer_username =
        peer_username.or_else(|| search_result.and_then(|entry| entry.peer_username.clone()));
    let source = if share.is_some() {
        "local-share"
    } else if transfer.is_some() {
        "transfer"
    } else if search_result.is_some() && family == "mesh" {
        "mesh-preview"
    } else if search_result.is_some() {
        "peer-preview"
    } else if family == "mesh" {
        "mesh-unresolved"
    } else {
        "peer-unresolved"
    };
    drop(searches);
    drop(transfers);
    drop(shares);

    let mut tickets = state.stream_tickets.write().await;
    let Some((token, ticket)) = tickets.issue(
        family,
        source,
        resolved_content_id,
        resolved_filename,
        resolved_peer_username,
        resolved_size,
        content_type,
        120,
    ) else {
        return Err("preview stream ticket capacity is full".to_owned());
    };
    if let Some((source_url, source_authorization, expected_hash)) = remote_mesh {
        if !tickets.configure_remote_mesh(&token, source_url, source_authorization, expected_hash) {
            return Err("preview stream ticket could not be configured".to_owned());
        }
    }
    drop(tickets);

    let body = serde_json::json!({
        "ticket": token,
        "streamUrl": format!("/api/v0/{family}-streams/{}", url_encode(&token)),
        "stream_url": format!("/api/v0/{family}-streams/{}", url_encode(&token)),
        "expiresInSeconds": 120,
        "contentType": ticket.content_type,
        "content_id": ticket.content_id,
        "filename": ticket.filename,
        "size": ticket.size,
        "source": ticket.source,
    })
    .to_string();
    Ok(body)
}

async fn open_preview_stream_ticket(state: &AppState, family: &str, token: &str) -> Option<String> {
    let mut tickets = state.stream_tickets.write().await;
    let ticket = tickets.get(token);
    drop(tickets);
    let ticket = ticket?;
    if ticket.family != family {
        return None;
    }
    Some(
        serde_json::json!({
            "ticket": token,
            "status": "available",
            "source": ticket.source,
            "content_id": ticket.content_id,
            "filename": ticket.filename,
            "peer_username": ticket.peer_username,
            "size": ticket.size,
            "contentType": ticket.content_type,
            "created_at": ticket.created_at,
            "expires_at": ticket.expires_at,
            "cacheControl": "no-store",
            "acceptRanges": "none",
        })
        .to_string(),
    )
}

fn preview_stream_content_type(path: &str) -> &'static str {
    match path
        .rsplit_once('.')
        .map(|(_, extension)| extension.to_ascii_lowercase())
    {
        Some(extension) if extension == "flac" => "audio/flac",
        Some(extension) if extension == "mp3" => "audio/mpeg",
        Some(extension) if extension == "ogg" || extension == "oga" => "audio/ogg",
        Some(extension) if extension == "opus" => "audio/ogg; codecs=opus",
        Some(extension) if extension == "wav" => "audio/wav",
        Some(extension) if extension == "m4a" || extension == "mp4" => "audio/mp4",
        _ => "application/octet-stream",
    }
}

fn native_compat_route(method: &str, path: &str) -> bool {
    matches!(
        (method, path),
        (
            "GET",
            "/api/slskdn"
                | "/api/slskdn/library/health"
                | "/api/hashdb"
                | "/api/hashdb/stats"
                | "/api/mesh"
                | "/api/mesh/health"
                | "/api/mesh/transport"
                | "/api/virtualsoulfind"
                | "/api/virtualsoulfind/canonical/status"
                | "/api/audio"
                | "/api/mediacore"
                | "/api/playback"
                | "/api/security"
                | "/api/security/status"
                | "/api/pods"
                | "/api/solid"
                | "/api/solid/status"
                | "/api/federation"
                | "/api/federation/diagnostics"
        ) | (
            "POST",
            "/api/slskdn/warm-cache" | "/api/audio/variants/dedupe" | "/api/mediacore/retrieve"
        )
    )
}

async fn native_compat_response(method: &str, path: &str, state: &AppState) -> HttpResponse {
    let session = state.session.read().await;
    let shares = state.shares.read().await;
    let searches = state.searches.read().await;
    let transfers = state.transfers.read().await;
    let listeners = state.listeners.read().await;
    let users = state.users.read().await;
    let rooms = state.rooms.read().await;
    let events = state.events.read().await;
    let library = state.library.read().await;
    let now_playing = state.now_playing.read().await;
    let security = state.security.read().await;
    let mesh = state.mesh.read().await;
    let collections = state.collections.read().await;
    let wishlist = state.wishlist.read().await;

    let family = path
        .trim_start_matches("/api/")
        .split('/')
        .next()
        .unwrap_or("native");
    let status = if method == "POST" || method == "PUT" || method == "DELETE" {
        "accepted"
    } else if family == "security" && security.active_bans() > 0 {
        "guarded"
    } else if family == "playback" && !now_playing.records.is_empty() {
        "playing"
    } else if family == "mesh" && (!users.records.is_empty() || !mesh.capability_records.is_empty())
    {
        "ready"
    } else if family == "solid" && (!collections.records.is_empty()) {
        "local"
    } else if matches!(family, "fairness" | "ranking")
        && (!transfers.entries.is_empty()
            || !searches.records.is_empty()
            || !users.records.is_empty())
    {
        "ready"
    } else if family == "portforwarding"
        && (listeners.regular_bind.is_some() || listeners.obfuscated_bind.is_some())
    {
        "configured"
    } else if family == "portforwarding" {
        "disabled"
    } else if family == "federation"
        && (!mesh.capability_records.is_empty() || !users.records.is_empty())
    {
        "ready"
    } else if session.state == "connected"
        || !shares.entries.is_empty()
        || !searches.records.is_empty()
    {
        "local"
    } else {
        "empty"
    };
    let jobs = searches
        .records
        .iter()
        .map(|record| {
            serde_json::json!({
                "id": record.id,
                "token": record.token,
                "kind": "search",
                "status": record.status,
                "query": record.query,
            })
        })
        .chain(transfers.entries.iter().map(|entry| {
            serde_json::json!({
                "id": format!("transfer-{}", entry.id),
                "kind": "transfer",
                "status": entry.status,
                "filename": entry.filename,
                "username": entry.peer_username,
            })
        }))
        .collect::<Vec<_>>();
    let items = match family {
        "library" => library
            .records
            .iter()
            .map(|record| {
                serde_json::from_str::<serde_json::Value>(&record.json())
                    .unwrap_or_else(|_| serde_json::json!({ "id": record.id }))
            })
            .collect::<Vec<_>>(),
        "playback" => now_playing
            .records
            .iter()
            .map(|record| {
                serde_json::from_str::<serde_json::Value>(&record.json())
                    .unwrap_or_else(|_| serde_json::json!({}))
            })
            .collect::<Vec<_>>(),
        "security" => security
            .json_value()
            .get("bans")
            .and_then(serde_json::Value::as_array)
            .cloned()
            .unwrap_or_default(),
        "fairness" => users
            .records
            .iter()
            .map(|user| {
                let queued = transfers
                    .entries
                    .iter()
                    .filter(|entry| {
                        entry.peer_username.as_deref() == Some(user.username.as_str())
                            && matches!(entry.status.as_str(), "queued" | "in_progress" | "requested")
                    })
                    .count();
                serde_json::json!({
                    "username": user.username,
                    "watched": user.watched,
                    "status": user.status,
                    "averageSpeed": user.average_speed.unwrap_or(0),
                    "queuedTransfers": queued,
                    "score": user.average_speed.unwrap_or(0) as u64 + user.file_count.unwrap_or(0) as u64,
                })
            })
            .collect::<Vec<_>>(),
        "ranking" => {
            let mut rows = transfers
                .entries
                .iter()
                .map(|entry| {
                    serde_json::json!({
                        "id": format!("transfer-{}", entry.id),
                        "kind": "transfer",
                        "score": entry.bytes_transferred,
                        "filename": entry.filename,
                        "username": entry.peer_username,
                        "status": entry.status,
                    })
                })
                .chain(searches.records.iter().map(|record| {
                    serde_json::json!({
                        "id": record.id,
                        "kind": "search",
                        "score": record.results.len(),
                        "query": record.query,
                        "status": record.status,
                    })
                }))
                .collect::<Vec<_>>();
            rows.sort_by(|a, b| {
                b.get("score")
                    .and_then(serde_json::Value::as_u64)
                    .cmp(&a.get("score").and_then(serde_json::Value::as_u64))
            });
            rows
        }
        "portforwarding" => vec![serde_json::json!({
            "regularBind": listeners.regular_bind,
            "regularLocalAddr": listeners.regular_local_addr,
            "obfuscatedBind": listeners.obfuscated_bind,
            "obfuscatedLocalAddr": listeners.obfuscated_local_addr,
            "regularAccepts": listeners.regular_accepts,
            "obfuscatedAccepts": listeners.obfuscated_accepts,
            "errors": listeners.errors,
            "lastError": public_listener_error(listeners.last_error.as_deref()),
            "updated_at": listeners.updated_at,
        })],
        "solid" => collections
            .records
            .iter()
            .map(|collection| {
                serde_json::json!({
                    "id": collection.id,
                    "name": collection.name,
                    "itemCount": collection.items.len(),
                    "updated_at": collection.updated_at,
                    "storage": "local-collection",
                })
            })
            .collect::<Vec<_>>(),
        "federation" => mesh
            .capability_records
            .iter()
            .map(|record| {
                serde_json::json!({
                    "username": record.username,
                    "issuedAt": record.issued_at_unix,
                    "expiresAt": record.expires_at_unix,
                    "features": record.features.clone(),
                    "endpoints": record.endpoints.clone(),
                    "source": "peer-capability",
                })
            })
            .chain(users.records.iter().filter(|user| user.watched).map(|user| {
                serde_json::json!({
                    "username": user.username,
                    "status": user.status,
                    "source": "watched-user",
                })
            }))
            .collect::<Vec<_>>(),
        "pods" | "podcore" | "listening-party" => rooms
            .records
            .iter()
            .map(|room| {
                serde_json::json!({
                    "id": room.name,
                    "name": room.name,
                    "joined": room.joined,
                    "messageCount": room.messages.len(),
                    "userCount": room.user_count,
                })
            })
            .collect::<Vec<_>>(),
        "hashdb" | "streams" | "audio" | "mediacore" => shares
            .entries
            .iter()
            .take(DEFAULT_LIST_LIMIT)
            .map(|entry| {
                serde_json::json!({
                    "filename": entry.filename,
                    "size": entry.size,
                    "extension": entry.extension,
                })
            })
            .collect::<Vec<_>>(),
        "discovery" | "signals" | "traces" => events
            .records
            .iter()
            .rev()
            .take(50)
            .map(|event| {
                serde_json::json!({
                    "id": event.id,
                    "kind": event.kind,
                    "resource": event.resource,
                    "created_at": event.created_at,
                })
            })
            .collect::<Vec<_>>(),
        _ => users
            .records
            .iter()
            .map(|user| {
                serde_json::json!({
                    "username": user.username,
                    "status": user.status,
                    "watched": user.watched,
                })
            })
            .collect::<Vec<_>>(),
    };
    let item_count = items.len();
    let job_count = jobs.len();
    let body = serde_json::json!({
        "path": path,
        "method": method,
        "family": family,
        "status": status,
        "enabled": true,
        "supported": true,
        "connected": session.state == "connected",
        "items": items,
        "itemCount": item_count,
        "jobs": jobs,
        "jobCount": job_count,
        "counts": {
            "connected": session.state == "connected",
            "shares": shares.entries.len(),
            "searches": searches.records.len(),
            "transfers": transfers.entries.len(),
            "activeTransfers": transfers.entries.iter().filter(|entry| matches!(entry.status.as_str(), "queued" | "in_progress" | "requested")).count(),
            "users": users.records.len(),
            "watchedUsers": users.records.iter().filter(|user| user.watched).count(),
            "rooms": rooms.records.len(),
            "joinedRooms": rooms.records.iter().filter(|room| room.joined).count(),
            "events": events.records.len(),
            "libraryItems": library.records.len(),
            "wishlistItems": wishlist.records.iter().map(|record| record.items.len()).sum::<usize>(),
            "securityBans": security.active_bans(),
            "meshCapabilities": mesh.capability_records.len(),
            "collections": collections.records.len(),
            "listenerAccepts": listeners.regular_accepts + listeners.obfuscated_accepts,
            "listenerErrors": listeners.errors,
        },
    })
    .to_string();

    drop(wishlist);
    drop(collections);
    drop(mesh);
    drop(security);
    drop(now_playing);
    drop(library);
    drop(events);
    drop(rooms);
    drop(users);
    drop(listeners);
    drop(transfers);
    drop(searches);
    drop(shares);
    drop(session);

    if method == "POST" {
        routing::accepted_response(body)
    } else {
        routing::ok_response(body)
    }
}

fn conversation_message_path(path: &str) -> Option<(&str, u64)> {
    let rest = path.strip_prefix("/api/conversations/")?;
    let (username, id) = rest.split_once('/')?;
    if username.is_empty() || username.contains('/') || id.contains('/') {
        return None;
    }
    Some((username, id.parse().ok()?))
}

fn conversation_messages_path(path: &str) -> Option<&str> {
    path.strip_prefix("/api/conversations/")?
        .strip_suffix("/messages")
        .filter(|username| !username.is_empty() && !username.contains('/'))
}

fn slskd_user_file_json(entry: &BrowseEntry) -> serde_json::Value {
    serde_json::json!({
        "filename": entry.filename,
        "size": entry.size,
        "code": 1,
        "extension": entry.extension,
        "attributeCount": 0,
        "attributes": [],
    })
}

fn slskd_share_file_json(entry: &FileEntry) -> serde_json::Value {
    serde_json::json!({
        "filename": entry.filename,
        "size": entry.size,
        "code": 1,
        "extension": entry.extension,
        "attributeCount": 0,
        "attributes": [],
    })
}

fn share_entry_matches_prefix(entry: &FileEntry, share_id: &str) -> bool {
    share_id.is_empty()
        || share_id == "shares"
        || entry.filename == share_id
        || entry
            .filename
            .strip_prefix(share_id)
            .is_some_and(|rest| rest.starts_with('/'))
}

fn slskd_share_directories_json(entries: &[FileEntry], share_id: Option<&str>) -> String {
    let filtered = entries
        .iter()
        .filter(|entry| share_id.is_none_or(|share_id| share_entry_matches_prefix(entry, share_id)))
        .cloned()
        .collect::<Vec<_>>();
    let directories = group_share_entries(&filtered)
        .into_iter()
        .map(|(name, files)| {
            serde_json::json!({
                "name": name,
                "fileCount": files.len(),
                "files": files.iter().map(slskd_share_file_json).collect::<Vec<_>>(),
            })
        })
        .collect::<Vec<_>>();
    serde_json::Value::Array(directories).to_string()
}

fn slskd_user_directories_json(
    directory: &str,
    entries: &[BrowseEntry],
    query: Option<&str>,
) -> String {
    let filter = RecordListFilter::from_query(query);
    let files = entries
        .iter()
        .filter(|entry| virtual_folder(&entry.filename) == directory)
        .collect::<Vec<_>>();
    let file_count = files.len();
    let filtered_files = files
        .into_iter()
        .filter(|entry| {
            filter
                .q
                .as_deref()
                .is_none_or(|q| entry.filename.to_ascii_lowercase().contains(q))
        })
        .collect::<Vec<_>>();
    let filtered_file_count = filtered_files.len();
    let total_bytes = filtered_files.iter().map(|entry| entry.size).sum::<u64>();
    let files = filtered_files
        .into_iter()
        .skip(filter.offset)
        .take(filter.limit.unwrap_or(usize::MAX))
        .map(slskd_user_file_json)
        .collect::<Vec<_>>();
    serde_json::Value::Array(vec![serde_json::json!({
        "name": directory,
        "fileCount": file_count,
        "filteredFileCount": filtered_file_count,
        "totalBytes": total_bytes,
        "files": files,
        "offset": filter.offset,
        "limit": filter.limit,
    })])
    .to_string()
}

fn slskd_user_root_json(entries: &[BrowseEntry], query: Option<&str>) -> String {
    let filter = RecordListFilter::from_query(query);
    let grouped = group_browse_entries(entries);
    let directory_count = grouped.len();
    let total_file_count = grouped.iter().map(|(_, files)| files.len()).sum::<usize>();
    let filtered = grouped
        .into_iter()
        .filter(|(name, files)| {
            filter.q.as_deref().is_none_or(|q| {
                name.to_ascii_lowercase().contains(q)
                    || files
                        .iter()
                        .any(|entry| entry.filename.to_ascii_lowercase().contains(q))
            })
        })
        .collect::<Vec<_>>();
    let filtered_directory_count = filtered.len();
    let filtered_file_count = filtered
        .iter()
        .map(|(name, files)| {
            if let Some(q) = filter.q.as_deref() {
                if name.to_ascii_lowercase().contains(q) {
                    return files.len();
                }
                files
                    .iter()
                    .filter(|entry| entry.filename.to_ascii_lowercase().contains(q))
                    .count()
            } else {
                files.len()
            }
        })
        .sum::<usize>();
    let filtered_total_bytes = filtered
        .iter()
        .map(|(name, files)| {
            if let Some(q) = filter.q.as_deref() {
                if name.to_ascii_lowercase().contains(q) {
                    return files.iter().map(|entry| entry.size).sum::<u64>();
                }
                files
                    .iter()
                    .filter(|entry| entry.filename.to_ascii_lowercase().contains(q))
                    .map(|entry| entry.size)
                    .sum::<u64>()
            } else {
                files.iter().map(|entry| entry.size).sum::<u64>()
            }
        })
        .sum::<u64>();
    let directories = filtered
        .into_iter()
        .skip(filter.offset)
        .take(filter.limit.unwrap_or(usize::MAX))
        .map(|(name, files)| {
            let directory_matched = filter
                .q
                .as_deref()
                .is_some_and(|q| name.to_ascii_lowercase().contains(q));
            let visible_files = files
                .iter()
                .filter(|entry| {
                    if directory_matched {
                        return true;
                    }
                    filter
                        .q
                        .as_deref()
                        .is_none_or(|q| entry.filename.to_ascii_lowercase().contains(q))
                })
                .collect::<Vec<_>>();
            serde_json::json!({
                "name": name,
                "fileCount": files.len(),
                "filteredFileCount": visible_files.len(),
                "totalBytes": visible_files.iter().map(|entry| entry.size).sum::<u64>(),
                "files": visible_files.iter().map(|entry| slskd_user_file_json(entry)).collect::<Vec<_>>(),
            })
        })
        .collect::<Vec<_>>();
    serde_json::json!({
        "directories": directories,
        "directoryCount": directory_count,
        "filteredDirectoryCount": filtered_directory_count,
        "fileCount": total_file_count,
        "filteredFileCount": filtered_file_count,
        "totalBytes": filtered_total_bytes,
        "offset": filter.offset,
        "limit": filter.limit,
        "lockedDirectories": [],
        "lockedDirectoryCount": 0,
    })
    .to_string()
}

fn slskd_empty_directory_json(name: &str) -> serde_json::Value {
    serde_json::json!({
        "name": name,
        "fullName": name,
        "attributes": "",
        "createdAt": "",
        "modifiedAt": "",
        "files": [],
        "directories": [],
    })
}

const SLSKD_STORAGE_DIRECT_LIST_DEFAULT_ENTRIES: usize = 1_024;
const SLSKD_STORAGE_DIRECT_LIST_MAX_ENTRIES: usize = 4_096;
const SLSKD_STORAGE_RECURSIVE_LIST_DEFAULT_ENTRIES: usize = 256;
const SLSKD_STORAGE_RECURSIVE_LIST_MAX_ENTRIES: usize = 1_024;
const SLSKD_STORAGE_MAX_SCANNED_DIRECTORY_ENTRIES: usize = 16_384;
const SLSKD_STORAGE_MAX_RECURSION_DEPTH: usize = 24;
const SLSKD_STORAGE_MAX_DELETE_DEPTH: usize = 64;
const SLSKD_STORAGE_MAX_DELETE_TOTAL_ENTRIES: usize = 65_536;
const STORAGE_DIRECTORY_ENTRY_LIMIT_ERROR: &str = "storage directory entry limit exceeded";
const STORAGE_DIRECTORY_DELETE_ENTRY_LIMIT_ERROR: &str =
    "storage directory delete entry limit exceeded";
const STORAGE_DIRECTORY_DELETE_TOTAL_LIMIT_ERROR: &str =
    "storage directory delete total entry limit exceeded";
const STORAGE_DIRECTORY_DELETE_DEPTH_ERROR: &str = "storage directory delete depth exceeded";

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
struct StorageDirectoryListOptions {
    recursive: bool,
    limit: usize,
    offset: usize,
}

impl StorageDirectoryListOptions {
    fn from_query(query: Option<&str>) -> Self {
        let recursive = query_bool(query, "recursive").unwrap_or(false);
        let default_limit = if recursive {
            SLSKD_STORAGE_RECURSIVE_LIST_DEFAULT_ENTRIES
        } else {
            SLSKD_STORAGE_DIRECT_LIST_DEFAULT_ENTRIES
        };
        let max_limit = if recursive {
            SLSKD_STORAGE_RECURSIVE_LIST_MAX_ENTRIES
        } else {
            SLSKD_STORAGE_DIRECT_LIST_MAX_ENTRIES
        };
        let mut options = Self {
            recursive,
            limit: default_limit,
            offset: 0,
        };
        for (name, value) in query_params(query.unwrap_or_default()) {
            match name.as_str() {
                "limit" => {
                    options.limit = value
                        .parse::<usize>()
                        .ok()
                        .filter(|limit| *limit > 0)
                        .map(|limit| limit.min(max_limit))
                        .unwrap_or(default_limit);
                }
                "offset" => options.offset = value.parse::<usize>().unwrap_or(0),
                _ => {}
            }
        }
        options
    }
}

#[derive(Debug)]
struct StorageDirectoryListState {
    options: StorageDirectoryListOptions,
    seen_top_level: usize,
    emitted: usize,
    truncated: bool,
}

impl StorageDirectoryListState {
    fn new(options: StorageDirectoryListOptions) -> Self {
        Self {
            options,
            seen_top_level: 0,
            emitted: 0,
            truncated: false,
        }
    }

    fn should_emit_top_level(&mut self) -> bool {
        self.seen_top_level += 1;
        self.seen_top_level > self.options.offset
    }

    fn reserve_entry(&mut self) -> bool {
        if self.emitted >= self.options.limit {
            self.truncated = true;
            return false;
        }
        self.emitted += 1;
        true
    }
}

fn reserve_storage_scan_entry(scanned: &mut usize) -> Result<(), String> {
    if *scanned >= SLSKD_STORAGE_MAX_SCANNED_DIRECTORY_ENTRIES {
        return Err(STORAGE_DIRECTORY_ENTRY_LIMIT_ERROR.to_owned());
    }
    *scanned += 1;
    Ok(())
}

fn reserve_storage_delete_entry(scanned: &mut usize, total: &mut usize) -> Result<(), String> {
    if *scanned >= SLSKD_STORAGE_MAX_SCANNED_DIRECTORY_ENTRIES {
        return Err(STORAGE_DIRECTORY_DELETE_ENTRY_LIMIT_ERROR.to_owned());
    }
    if *total >= SLSKD_STORAGE_MAX_DELETE_TOTAL_ENTRIES {
        return Err(STORAGE_DIRECTORY_DELETE_TOTAL_LIMIT_ERROR.to_owned());
    }
    *scanned += 1;
    *total += 1;
    Ok(())
}

fn query_bool(query: Option<&str>, key: &str) -> Option<bool> {
    query_params(query.unwrap_or_default())
        .into_iter()
        .find_map(|(name, value)| (name == key).then(|| parse_bool_value(&value))?)
}

#[cfg(not(unix))]
fn slskd_storage_file_json(path: &Path, root: &Path) -> serde_json::Value {
    let relative = path
        .strip_prefix(root)
        .ok()
        .and_then(|path| path.to_str())
        .unwrap_or_default()
        .replace('\\', "/");
    let name = path
        .file_name()
        .and_then(|name| name.to_str())
        .unwrap_or_default()
        .to_owned();
    let length = path.metadata().map(|metadata| metadata.len()).unwrap_or(0);
    serde_json::json!({
        "name": name,
        "fullName": relative,
        "length": length,
        "attributes": "",
        "createdAt": "",
        "modifiedAt": "",
    })
}

#[cfg(not(unix))]
fn slskd_storage_directory_value(
    root: &Path,
    directory: &Path,
    state: &mut StorageDirectoryListState,
    top_level: bool,
    depth: usize,
) -> Result<serde_json::Value, String> {
    let relative = directory
        .strip_prefix(root)
        .ok()
        .and_then(|path| path.to_str())
        .unwrap_or_default()
        .replace('\\', "/");
    let name = directory
        .file_name()
        .and_then(|name| name.to_str())
        .unwrap_or_default()
        .to_owned();
    if !directory.exists() {
        let display_name = if relative.is_empty() { name } else { relative };
        return Ok(slskd_empty_directory_json(&display_name));
    }
    let metadata = directory
        .symlink_metadata()
        .map_err(|error| format!("directory metadata failed: {error}"))?;
    if metadata.file_type().is_symlink() {
        return Err("storage path must not be a symlink".to_owned());
    }
    if !metadata.is_dir() {
        return Err("storage path is not a directory".to_owned());
    }

    let mut entries = Vec::new();
    let mut scanned = 0;
    for entry in
        fs::read_dir(directory).map_err(|error| format!("directory read failed: {error}"))?
    {
        let entry = entry.map_err(|error| format!("directory entry read failed: {error}"))?;
        reserve_storage_scan_entry(&mut scanned)?;
        entries.push(entry.path());
    }
    entries.sort_by(|left, right| left.file_name().cmp(&right.file_name()));

    let mut files = Vec::new();
    let mut directories = Vec::new();
    for path in entries {
        let metadata = path
            .symlink_metadata()
            .map_err(|error| format!("directory entry metadata failed: {error}"))?;
        if metadata.file_type().is_symlink() {
            continue;
        }
        if top_level && !state.should_emit_top_level() {
            continue;
        }
        if !state.reserve_entry() {
            break;
        }
        if metadata.is_file() {
            files.push(slskd_storage_file_json(&path, root));
        } else if metadata.is_dir() {
            if state.options.recursive && depth < SLSKD_STORAGE_MAX_RECURSION_DEPTH {
                directories.push(slskd_storage_directory_value(
                    root,
                    &path,
                    state,
                    false,
                    depth + 1,
                )?);
            } else {
                let child_relative = path
                    .strip_prefix(root)
                    .ok()
                    .and_then(|path| path.to_str())
                    .unwrap_or_default()
                    .replace('\\', "/");
                directories.push(slskd_empty_directory_json(&child_relative));
                if state.options.recursive {
                    state.truncated = true;
                }
            }
        }
    }
    files.sort_by(|left, right| left["fullName"].as_str().cmp(&right["fullName"].as_str()));
    directories.sort_by(|left, right| left["fullName"].as_str().cmp(&right["fullName"].as_str()));
    Ok(serde_json::json!({
        "name": name,
        "fullName": relative,
        "attributes": "",
        "createdAt": "",
        "modifiedAt": "",
        "files": files,
        "directories": directories,
        "offset": if top_level { state.options.offset } else { 0 },
        "limit": state.options.limit,
        "entryCount": state.emitted,
        "truncated": state.truncated,
    }))
}

fn slskd_storage_directory_json(
    root: &Path,
    encoded_name: Option<&str>,
    options: StorageDirectoryListOptions,
) -> Result<String, String> {
    fs::create_dir_all(root).map_err(|error| format!("storage root create failed: {error}"))?;
    let path = if let Some(encoded_name) = encoded_name {
        let decoded = decode_slskd_base64_path_segment(encoded_name)?;
        scoped_relative_storage_path(root, &decoded)?
    } else {
        root.to_path_buf()
    };
    #[cfg(unix)]
    {
        let relative = path
            .strip_prefix(root)
            .map_err(|_| "storage path is outside the storage root".to_owned())?;
        slskd_storage_directory_json_unix(root, relative, options)
    }
    #[cfg(not(unix))]
    {
        let canonical_root = root
            .canonicalize()
            .map_err(|error| format!("storage root canonicalize failed: {error}"))?;
        let canonical_parent = if path == root {
            canonical_root.clone()
        } else if path.exists() {
            path.parent()
                .unwrap_or(root)
                .canonicalize()
                .map_err(|error| format!("storage parent canonicalize failed: {error}"))?
        } else {
            path.parent()
                .unwrap_or(root)
                .canonicalize()
                .map_err(|error| format!("storage parent canonicalize failed: {error}"))?
        };
        if !canonical_parent.starts_with(&canonical_root) {
            return Err("path escapes the storage root".to_owned());
        }
        let mut state = StorageDirectoryListState::new(options);
        slskd_storage_directory_value(root, &path, &mut state, true, 0)
            .map(|value| value.to_string())
    }
}

#[cfg(unix)]
fn slskd_storage_directory_json_unix(
    root: &Path,
    relative: &Path,
    options: StorageDirectoryListOptions,
) -> Result<String, String> {
    use rustix::fs::{open, openat, Mode, OFlags};

    let directory_flags = OFlags::RDONLY | OFlags::DIRECTORY | OFlags::NOFOLLOW | OFlags::CLOEXEC;
    let mut directory = open(root, directory_flags, Mode::empty())
        .map_err(|error| format!("storage root confined open failed: {error}"))?;
    for component in relative.components() {
        let Component::Normal(component) = component else {
            return Err("storage path contains a non-relative component".to_owned());
        };
        directory = match openat(&directory, component, directory_flags, Mode::empty()) {
            Ok(directory) => directory,
            Err(error) if error == rustix::io::Errno::NOENT => {
                return Ok(slskd_empty_directory_json(&relative.to_string_lossy()).to_string());
            }
            Err(error) => return Err(format!("storage directory confined open failed: {error}")),
        };
    }
    let mut state = StorageDirectoryListState::new(options);
    slskd_storage_directory_value_unix(root, relative, &directory, &mut state, true, 0)
        .map(|value| value.to_string())
}

#[cfg(unix)]
fn slskd_storage_directory_value_unix(
    root: &Path,
    relative: &Path,
    directory: &impl std::os::fd::AsFd,
    state: &mut StorageDirectoryListState,
    top_level: bool,
    depth: usize,
) -> Result<serde_json::Value, String> {
    use rustix::fs::{openat, Dir, Mode, OFlags};
    use std::os::unix::ffi::OsStrExt;

    let directory_flags = OFlags::RDONLY | OFlags::DIRECTORY | OFlags::NOFOLLOW | OFlags::CLOEXEC;
    let file_flags = OFlags::RDONLY | OFlags::NONBLOCK | OFlags::NOFOLLOW | OFlags::CLOEXEC;
    let mut reader = Dir::read_from(directory)
        .map_err(|error| format!("storage directory read failed: {error}"))?;
    let mut names = Vec::new();
    let mut scanned = 0;
    while let Some(entry) = reader.read() {
        let entry = entry.map_err(|error| format!("storage directory entry failed: {error}"))?;
        if !matches!(entry.file_name().to_bytes(), b"." | b"..") {
            reserve_storage_scan_entry(&mut scanned)?;
            names.push(entry.file_name().to_owned());
        }
    }
    names.sort_by(|left, right| left.to_bytes().cmp(right.to_bytes()));

    let mut files = Vec::new();
    let mut directories = Vec::new();
    for name in names {
        let child_directory = openat(directory, &name, directory_flags, Mode::empty()).ok();
        let file_metadata = if child_directory.is_none() {
            openat(directory, &name, file_flags, Mode::empty())
                .ok()
                .and_then(|file| fs::File::from(file).metadata().ok())
                .filter(fs::Metadata::is_file)
        } else {
            None
        };
        if child_directory.is_none() && file_metadata.is_none() {
            continue;
        }
        if top_level && !state.should_emit_top_level() {
            continue;
        }
        if !state.reserve_entry() {
            break;
        }
        let name_os = std::ffi::OsStr::from_bytes(name.to_bytes());
        let child_relative = relative.join(name_os);
        if let Some(child) = child_directory {
            if state.options.recursive && depth < SLSKD_STORAGE_MAX_RECURSION_DEPTH {
                directories.push(slskd_storage_directory_value_unix(
                    root,
                    &child_relative,
                    &child,
                    state,
                    false,
                    depth + 1,
                )?);
            } else {
                directories.push(slskd_empty_directory_json(
                    &child_relative.to_string_lossy().replace('\\', "/"),
                ));
                if state.options.recursive {
                    state.truncated = true;
                }
            }
            continue;
        }
        let metadata = file_metadata.expect("validated file metadata");
        files.push(serde_json::json!({
            "name": name_os.to_string_lossy(),
            "fullName": child_relative.to_string_lossy().replace('\\', "/"),
            "length": metadata.len(),
            "attributes": "",
            "createdAt": "",
            "modifiedAt": "",
        }));
    }
    let name = relative
        .file_name()
        .or_else(|| root.file_name())
        .map(|value| value.to_string_lossy().into_owned())
        .unwrap_or_default();
    let relative = relative.to_string_lossy().replace('\\', "/");
    Ok(serde_json::json!({
        "name": name,
        "fullName": relative,
        "attributes": "",
        "createdAt": "",
        "modifiedAt": "",
        "files": files,
        "directories": directories,
        "offset": if top_level { state.options.offset } else { 0 },
        "limit": state.options.limit,
        "entryCount": state.emitted,
        "truncated": state.truncated,
    }))
}

fn slskd_transfer_summary_report(query: Option<&str>, transfers: &TransferQueue) -> String {
    let direction = slskd_transfer_query_direction(query);
    let username = slskd_transfer_query_username(query);
    let entries = transfers
        .entries
        .iter()
        .filter(|entry| slskd_transfer_matches_query(entry, direction, username.as_deref()))
        .collect::<Vec<_>>();
    let downloads = entries.iter().filter(|entry| entry.direction == 0).count();
    let uploads = entries.iter().filter(|entry| entry.direction == 1).count();
    let total_bytes = entries
        .iter()
        .map(|entry| entry.bytes_transferred)
        .sum::<u64>();
    let average_speed = average_transfer_speed_at(&entries, unix_timestamp());
    let mut by_state = BTreeMap::new();
    for entry in &entries {
        let state = slskd_transfer_state(&entry.status).to_owned();
        let count = by_state.entry(state).or_insert(0usize);
        *count += 1;
    }
    let by_state = by_state
        .into_iter()
        .map(|(state, count)| (state, serde_json::json!({ "count": count })))
        .collect::<BTreeMap<_, _>>();
    serde_json::json!({
        "count": entries.len(),
        "downloads": downloads,
        "uploads": uploads,
        "totalBytes": total_bytes,
        "averageSpeed": average_speed,
        "byDirection": {
            "Download": { "count": downloads },
            "Upload": { "count": uploads },
        },
        "byState": by_state,
    })
    .to_string()
}

fn slskd_transfer_query_direction(query: Option<&str>) -> Option<u32> {
    query_params(query.unwrap_or_default())
        .into_iter()
        .find_map(|(name, value)| {
            (name == "direction").then(|| match value.to_ascii_lowercase().as_str() {
                "download" | "0" => Some(0),
                "upload" | "1" => Some(1),
                _ => None,
            })?
        })
}

fn slskd_transfer_query_username(query: Option<&str>) -> Option<String> {
    query_params(query.unwrap_or_default())
        .into_iter()
        .find_map(|(name, value)| (name == "username" && !value.is_empty()).then_some(value))
}

fn slskd_transfer_query_limit_offset(query: Option<&str>) -> (usize, usize) {
    let mut limit = DEFAULT_LIST_LIMIT;
    let mut offset = 0usize;
    for (name, value) in query_params(query.unwrap_or_default()) {
        match name.as_str() {
            "limit" => limit = parse_list_limit(&value),
            "offset" => offset = value.parse::<usize>().unwrap_or(0),
            _ => {}
        }
    }
    (limit, offset)
}

fn slskd_transfer_query_value(query: Option<&str>, key: &str) -> Option<String> {
    query_params(query.unwrap_or_default())
        .into_iter()
        .find_map(|(name, value)| {
            (name.eq_ignore_ascii_case(key) && !value.is_empty()).then_some(value)
        })
}

fn slskd_transfer_matches_query(
    entry: &TransferEntry,
    direction: Option<u32>,
    username: Option<&str>,
) -> bool {
    direction.is_none_or(|direction| entry.direction == direction)
        && username.is_none_or(|username| entry.peer_username.as_deref() == Some(username))
}

fn slskd_transfer_speeds_json(transfers: &TransferQueue) -> String {
    let now = unix_timestamp();
    let active_downloads = transfers
        .entries
        .iter()
        .filter(|entry| entry.direction == 0 && is_active_transfer_status(&entry.status))
        .count();
    let active_uploads = transfers
        .entries
        .iter()
        .filter(|entry| entry.direction == 1 && is_active_transfer_status(&entry.status))
        .count();
    let download_bytes = transfers
        .entries
        .iter()
        .filter(|entry| entry.direction == 0)
        .map(|entry| entry.bytes_transferred)
        .sum::<u64>();
    let upload_bytes = transfers
        .entries
        .iter()
        .filter(|entry| entry.direction == 1)
        .map(|entry| entry.bytes_transferred)
        .sum::<u64>();
    let download_speed = transfers
        .entries
        .iter()
        .filter(|entry| entry.direction == 0 && is_active_transfer_status(&entry.status))
        .map(|entry| entry.average_speed_at(now))
        .sum::<f64>();
    let upload_speed = transfers
        .entries
        .iter()
        .filter(|entry| entry.direction == 1 && is_active_transfer_status(&entry.status))
        .map(|entry| entry.average_speed_at(now))
        .sum::<f64>();
    let total_speed = download_speed + upload_speed;
    let active_transfers = active_downloads + active_uploads;
    let average_speed = if active_transfers == 0 {
        0.0
    } else {
        total_speed / active_transfers as f64
    };
    serde_json::json!({
        "active_transfers": active_transfers,
        "activeDownloads": active_downloads,
        "activeUploads": active_uploads,
        "total_bytes_transferred": download_bytes.saturating_add(upload_bytes),
        "downloadBytesTransferred": download_bytes,
        "uploadBytesTransferred": upload_bytes,
        "downloadSpeed": download_speed,
        "uploadSpeed": upload_speed,
        "average_speed": average_speed,
        "total": total_speed,
        "soulseek": total_speed,
        "mesh": 0.0,
        "download": download_speed,
        "upload": upload_speed,
        "sessionBytesDownloaded": download_bytes,
        "sessionBytesUploaded": upload_bytes,
        "sessionBytesTotal": download_bytes.saturating_add(upload_bytes),
    })
    .to_string()
}

fn average_transfer_speed_at(entries: &[&TransferEntry], now: u64) -> f64 {
    if entries.is_empty() {
        return 0.0;
    }
    entries
        .iter()
        .map(|entry| entry.average_speed_at(now))
        .sum::<f64>()
        / entries.len() as f64
}

fn slskd_download_stats_json(transfers: &TransferQueue) -> String {
    let downloads = transfers
        .entries
        .iter()
        .filter(|entry| entry.direction == 0)
        .collect::<Vec<_>>();
    let queued = downloads
        .iter()
        .filter(|entry| entry.status == "queued")
        .count();
    let active = downloads
        .iter()
        .filter(|entry| is_active_transfer_status(&entry.status))
        .count();
    let completed = downloads
        .iter()
        .filter(|entry| matches!(entry.status.as_str(), "succeeded" | "completed"))
        .count();
    let failed = downloads
        .iter()
        .filter(|entry| matches!(entry.status.as_str(), "failed" | "rejected"))
        .count();
    let cancelled = downloads
        .iter()
        .filter(|entry| entry.status == "cancelled")
        .count();
    let total_size = downloads
        .iter()
        .map(|entry| entry.size.unwrap_or(0))
        .sum::<u64>();
    let bytes_transferred = downloads
        .iter()
        .map(|entry| entry.bytes_transferred)
        .sum::<u64>();
    serde_json::json!({
        "total_downloads": downloads.len(),
        "totalDownloads": downloads.len(),
        "queued": queued,
        "active": active,
        "completed": completed,
        "failed": failed,
        "cancelled": cancelled,
        "total_size": total_size,
        "totalSize": total_size,
        "bytes_transferred": bytes_transferred,
        "bytesTransferred": bytes_transferred,
    })
    .to_string()
}

fn slskd_accelerated_downloads_json(query: Option<&str>, transfers: &TransferQueue) -> String {
    let username = slskd_transfer_query_username(query);
    let (limit, offset) = slskd_transfer_query_limit_offset(query);
    let mut candidates = transfers
        .entries
        .iter()
        .filter(|entry| entry.direction == 0)
        .filter(|entry| slskd_transfer_matches_query(entry, None, username.as_deref()))
        .filter(|entry| {
            matches!(
                entry.status.as_str(),
                "queued" | "peer_lookup" | "peer_negotiating" | "indirect_pending" | "in_progress"
            )
        })
        .collect::<Vec<_>>();
    candidates.sort_by(|left, right| {
        left.requested_at
            .cmp(&right.requested_at)
            .then_with(|| left.id.cmp(&right.id))
    });
    let count = candidates.len();
    let accelerated = candidates
        .into_iter()
        .skip(offset)
        .take(limit)
        .map(|entry| {
            serde_json::json!({
                "id": entry.id.to_string(),
                "username": entry.peer_username.as_deref().unwrap_or_default(),
                "filename": entry.filename,
                "state": slskd_transfer_state(&entry.status),
                "bytesTransferred": entry.bytes_transferred,
                "size": entry.size.unwrap_or(0),
                "position": transfers.slskd_transfer_position(0, entry.peer_username.as_deref().unwrap_or_default(), entry.id),
            })
        })
        .collect::<Vec<_>>();
    serde_json::json!({
        "enabled": false,
        "available": count > 0,
        "accelerated": accelerated,
        "count": count,
        "offset": offset,
        "limit": limit,
    })
    .to_string()
}

fn slskd_stuck_downloads_json(query: Option<&str>, transfers: &TransferQueue) -> String {
    let username = slskd_transfer_query_username(query);
    let (limit, offset) = slskd_transfer_query_limit_offset(query);
    let mut entries = transfers
        .entries
        .iter()
        .filter(|entry| entry.direction == 0)
        .filter(|entry| slskd_transfer_matches_query(entry, None, username.as_deref()))
        .filter(|entry| {
            matches!(entry.status.as_str(), "failed" | "rejected")
                || (is_active_transfer_status(&entry.status) && entry.bytes_transferred == 0)
        })
        .collect::<Vec<_>>();
    entries.sort_by(|left, right| {
        right
            .updated_at
            .cmp(&left.updated_at)
            .then_with(|| left.filename.cmp(&right.filename))
            .then_with(|| left.id.cmp(&right.id))
    });
    let count = entries.len();
    let stuck = entries
        .into_iter()
        .skip(offset)
        .take(limit)
        .map(|entry| {
            serde_json::json!({
                "id": entry.id.to_string(),
                "username": entry.peer_username.as_deref().unwrap_or_default(),
                "filename": entry.filename,
                "state": slskd_transfer_state(&entry.status),
                "bytesTransferred": entry.bytes_transferred,
                "size": entry.size.unwrap_or(0),
                "reason": public_transfer_reason(&entry.status, entry.reason.as_deref()).unwrap_or(""),
                "updatedAt": entry.updated_at.to_string(),
            })
        })
        .collect::<Vec<_>>();
    serde_json::json!({
        "stuck": stuck,
        "count": count,
        "offset": offset,
        "limit": limit,
    })
    .to_string()
}

fn slskd_download_user_stats_json(query: Option<&str>, transfers: &TransferQueue) -> String {
    let username_filter = slskd_transfer_query_username(query);
    let (limit, offset) = slskd_transfer_query_limit_offset(query);
    let mut grouped: BTreeMap<String, (usize, usize, usize, usize, u64, u64)> = BTreeMap::new();
    for entry in transfers
        .entries
        .iter()
        .filter(|entry| entry.direction == 0)
        .filter(|entry| slskd_transfer_matches_query(entry, None, username_filter.as_deref()))
    {
        let stats = grouped
            .entry(entry.peer_username.clone().unwrap_or_default())
            .or_insert((0, 0, 0, 0, 0, 0));
        stats.0 += 1;
        if entry.status == "queued" {
            stats.1 += 1;
        }
        if is_active_transfer_status(&entry.status) {
            stats.2 += 1;
        }
        if matches!(
            entry.status.as_str(),
            "succeeded" | "completed" | "cancelled" | "failed" | "rejected"
        ) {
            stats.3 += 1;
        }
        stats.4 = stats.4.saturating_add(entry.bytes_transferred);
        stats.5 = stats.5.saturating_add(entry.size.unwrap_or(0));
    }
    let mut users = grouped
        .into_iter()
        .map(
            |(username, (total, queued, active, terminal, bytes_transferred, total_size))| {
                serde_json::json!({
                    "username": username,
                    "total": total,
                    "queued": queued,
                    "active": active,
                    "terminal": terminal,
                    "bytesTransferred": bytes_transferred,
                    "totalSize": total_size,
                })
            },
        )
        .collect::<Vec<_>>();
    users.sort_by(|left, right| {
        right["total"]
            .as_u64()
            .cmp(&left["total"].as_u64())
            .then_with(|| left["username"].as_str().cmp(&right["username"].as_str()))
    });
    let count = users.len();
    let users = users
        .into_iter()
        .skip(offset)
        .take(limit)
        .collect::<Vec<_>>();
    serde_json::json!({
        "users": users,
        "count": count,
        "offset": offset,
        "limit": limit,
    })
    .to_string()
}

#[derive(Clone, Debug, Serialize)]
#[serde(rename_all = "camelCase")]
struct PodJoinSignatureInput {
    pod_id: String,
    peer_id: String,
    requested_role: String,
    timestamp_unix_ms: u64,
    message: String,
    nonce: String,
    signature: String,
    public_key: String,
}

impl PodJoinSignatureInput {
    fn from_json(body: &str) -> Result<Self, String> {
        serde_json::from_str::<serde_json::Value>(body)
            .map_err(|error| format!("invalid pod join JSON: {error}"))?;
        let input = Self {
            pod_id: extract_json_string_field(body, "podId")
                .or_else(|| extract_json_string_field(body, "pod"))
                .or_else(|| extract_json_string_field(body, "room"))
                .unwrap_or_default()
                .trim()
                .to_owned(),
            peer_id: extract_json_string_field(body, "peerId")
                .unwrap_or_default()
                .trim()
                .to_owned(),
            requested_role: extract_json_string_field(body, "requestedRole")
                .unwrap_or_else(|| "member".to_owned())
                .trim()
                .to_owned(),
            timestamp_unix_ms: extract_json_u64_field(body, "timestampUnixMs").unwrap_or(0),
            message: extract_json_string_field(body, "message")
                .unwrap_or_default()
                .trim()
                .to_owned(),
            nonce: extract_json_string_field(body, "nonce")
                .unwrap_or_default()
                .trim()
                .to_owned(),
            signature: extract_json_string_field(body, "signature")
                .unwrap_or_default()
                .trim()
                .to_owned(),
            public_key: extract_json_string_field(body, "publicKey")
                .unwrap_or_default()
                .trim()
                .to_owned(),
        };
        for (name, value, limit) in [
            ("podId", input.pod_id.as_str(), 512usize),
            ("peerId", input.peer_id.as_str(), 512),
            ("requestedRole", input.requested_role.as_str(), 128),
            ("message", input.message.as_str(), 4 * 1024),
            ("nonce", input.nonce.as_str(), 512),
            ("signature", input.signature.as_str(), 1024),
            ("publicKey", input.public_key.as_str(), 512),
        ] {
            if value.len() > limit {
                return Err(format!("pod join {name} exceeds {limit} bytes"));
            }
        }
        if [
            &input.pod_id,
            &input.peer_id,
            &input.requested_role,
            &input.message,
            &input.nonce,
        ]
        .iter()
        .any(|value| value.contains('|'))
        {
            return Err(
                "pod join signed fields must not contain the canonical delimiter".to_owned(),
            );
        }
        if input.pod_id.trim().is_empty() {
            return Err("pod join podId is required".to_owned());
        }
        if input.peer_id.trim().is_empty() {
            return Err("pod join peerId is required".to_owned());
        }
        Ok(input)
    }

    fn canonical_payload(&self) -> String {
        format!(
            "1|join-request|{}|{}|{}|{}|{}|{}",
            self.pod_id,
            self.peer_id,
            self.requested_role,
            self.timestamp_unix_ms,
            self.message,
            self.nonce
        )
    }
}

