async fn negotiate_plain_peer_transfer(
    address: SocketAddr,
    username: String,
    message: PeerMessage,
    transfer: &TransferEntry,
    timeout: Duration,
) -> Result<PeerTransferNegotiation, String> {
    let mut peer = time::timeout(timeout, connect_peer_messages(address, username))
        .await
        .map_err(|_| "plain peer connect timed out".to_owned())?
        .map_err(|error| format!("plain peer connect failed: {error}"))?;
    time::timeout(timeout, peer.send(&message))
        .await
        .map_err(|_| "plain peer transfer request timed out".to_owned())?
        .map_err(|error| format!("plain peer transfer request failed: {error}"))?;
    let response = time::timeout(timeout, peer.receive())
        .await
        .map_err(|_| "plain peer transfer response timed out".to_owned())?
        .map_err(|error| format!("plain peer transfer response failed: {error}"))?;
    handle_peer_transfer_negotiation_response(&mut peer, response, transfer, timeout).await
}

async fn negotiate_obfuscated_peer_transfer(
    address: SocketAddr,
    username: String,
    message: PeerMessage,
    transfer: &TransferEntry,
    timeout: Duration,
) -> Result<PeerTransferNegotiation, String> {
    let stream = time::timeout(timeout, TcpStream::connect(address))
        .await
        .map_err(|_| "obfuscated peer connect timed out".to_owned())?
        .map_err(|error| format!("obfuscated peer connect failed: {error}"))?;
    let stream = time::timeout(
        timeout,
        send_obfuscated_peer_init(stream, username, ConnectionKind::PeerMessages),
    )
    .await
    .map_err(|_| "obfuscated peer init timed out".to_owned())?
    .map_err(|error| format!("obfuscated peer init failed: {error}"))?;
    let mut peer = ObfuscatedPeerMessageConnection::new(stream);
    time::timeout(timeout, peer.send(&message))
        .await
        .map_err(|_| "obfuscated peer transfer request timed out".to_owned())?
        .map_err(|error| format!("obfuscated peer transfer request failed: {error}"))?;
    let response = time::timeout(timeout, peer.receive())
        .await
        .map_err(|_| "obfuscated peer transfer response timed out".to_owned())?
        .map_err(|error| format!("obfuscated peer transfer response failed: {error}"))?;
    handle_peer_transfer_negotiation_response(&mut peer, response, transfer, timeout).await
}

async fn handle_peer_transfer_negotiation_response<C>(
    peer: &mut C,
    response: PeerMessage,
    transfer: &TransferEntry,
    timeout: Duration,
) -> Result<PeerTransferNegotiation, String>
where
    C: PeerMessageSenderReceiver,
{
    let PeerMessage::TransferResponse(response) = response else {
        return Err(format!(
            "expected TransferResponse, got {}",
            peer_message_name(&response)
        ));
    };
    match response {
        TransferResponse::Allowed { token, size } => Ok(PeerTransferNegotiation::Allowed {
            token,
            size: size.or(transfer.size),
        }),
        TransferResponse::Rejected { token, reason }
            if token == transfer.token
                && transfer.direction == 0
                && is_remote_queue_response(&reason) =>
        {
            let queued = time::timeout(timeout, peer.receive_peer_message())
                .await
                .map_err(|_| "queued transfer request timed out".to_owned())?
                .map_err(|error| format!("queued transfer request failed: {error}"))?;
            let PeerMessage::TransferRequest(request) = queued else {
                return Err(format!(
                    "expected queued TransferRequest, got {}",
                    peer_message_name(&queued)
                ));
            };
            if request.direction != 1
                || request.token != transfer.token
                || request.filename != transfer.filename
            {
                return Err("queued transfer request did not match pending download".to_owned());
            }
            peer.send_peer_message(&PeerMessage::TransferResponse(TransferResponse::Allowed {
                token: request.token,
                size: request.size.or(transfer.size),
            }))
            .await
            .map_err(|error| format!("queued transfer response failed: {error}"))?;
            Ok(PeerTransferNegotiation::QueuedInbound {
                token: request.token,
                size: request.size.or(transfer.size),
            })
        }
        TransferResponse::Rejected { token, reason } => {
            Ok(PeerTransferNegotiation::Rejected { token, reason })
        }
    }
}

trait PeerMessageSenderReceiver {
    async fn receive_peer_message(&mut self) -> Result<PeerMessage, String>;
    async fn send_peer_message(&mut self, message: &PeerMessage) -> Result<(), String>;
}

impl PeerMessageSenderReceiver for PeerMessageConnection<TcpStream> {
    async fn receive_peer_message(&mut self) -> Result<PeerMessage, String> {
        self.receive()
            .await
            .map_err(|error| format!("plain peer receive failed: {error}"))
    }

    async fn send_peer_message(&mut self, message: &PeerMessage) -> Result<(), String> {
        self.send(message)
            .await
            .map_err(|error| format!("plain peer send failed: {error}"))
    }
}

impl PeerMessageSenderReceiver for ObfuscatedPeerMessageConnection<TcpStream> {
    async fn receive_peer_message(&mut self) -> Result<PeerMessage, String> {
        self.receive()
            .await
            .map_err(|error| format!("obfuscated peer receive failed: {error}"))
    }

    async fn send_peer_message(&mut self, message: &PeerMessage) -> Result<(), String> {
        self.send(message)
            .await
            .map_err(|error| format!("obfuscated peer send failed: {error}"))
    }
}

fn browse_entries_from_peer_message(message: PeerMessage) -> Result<Vec<BrowseEntry>, String> {
    match message {
        PeerMessage::SharedFileListResponse(payload) => parse_shared_file_list_payload(&payload),
        other => Err(format!(
            "expected SharedFileListResponse, got {}",
            peer_message_name(&other)
        )),
    }
}

fn folder_entries_from_peer_message(
    message: PeerMessage,
    folder: &str,
    folder_encoding: ProtocolTextEncoding,
) -> Result<Vec<BrowseEntry>, String> {
    match message {
        PeerMessage::FolderContentsResponse(payload) => {
            match parse_shared_file_list_payload(&payload) {
                Ok(entries) if !entries.is_empty() => Ok(entries),
                Ok(_) => parse_folder_file_list_payload(&payload, folder, folder_encoding),
                Err(_) => parse_folder_file_list_payload(&payload, folder, folder_encoding),
            }
        }
        other => Err(format!(
            "expected FolderContentsResponse, got {}",
            peer_message_name(&other)
        )),
    }
}

async fn send_session_command(state: &AppState, command: SessionCommand) -> Result<(), String> {
    state
        .session_commands
        .send(command)
        .await
        .map_err(|_| "session manager is not running".to_owned())
}

fn try_send_session_command(state: &AppState, command: SessionCommand) -> Result<(), String> {
    state
        .session_commands
        .try_send(command)
        .map_err(|error| format!("session command queue rejected request: {error}"))
}

async fn update_session<F>(state: &AppState, update: F)
where
    F: FnOnce(&mut SessionSnapshot),
{
    let mut snapshot = state.session.write().await;
    update(&mut snapshot);
    snapshot.updated_at = unix_timestamp();
}

async fn update_listeners<F>(state: &AppState, update: F)
where
    F: FnOnce(&mut ListenerSnapshot),
{
    let mut snapshot = state.listeners.write().await;
    update(&mut snapshot);
    snapshot.updated_at = unix_timestamp();
}

async fn record_transfer_rejection(
    state: &AppState,
    direction: u32,
    token: u32,
    filename: String,
    size: Option<u64>,
    reason: String,
) {
    let mut transfers = state.transfers.write().await;
    transfers.record_rejected_request(direction, token, filename, size, reason);
}

async fn record_event(
    state: &AppState,
    kind: impl Into<String>,
    resource: impl Into<String>,
    detail: Option<String>,
) {
    let kind = kind.into();
    let detail = if kind == "browse.failed" && detail.is_some() {
        Some("browse failed".to_owned())
    } else {
        detail
    };
    let mut events = state.events.write().await;
    let record = events.record(kind, resource, detail);
    drop(events);
    if let Err(error) = persist_event_record_checked(state, &record).await {
        update_session(state, |snapshot| {
            snapshot.last_error = Some(error);
        })
        .await;
    }
    let _ = state.event_tx.send(record);
}

async fn record_daemon_log(
    state: &AppState,
    level: logging::LogLevel,
    category: &str,
    message: impl Into<String>,
) {
    let message = message.into();
    let configured_level = *state.log_level.read().await;
    if configured_level <= level {
        eprintln!(
            "[{}] {}: {}",
            logging::LogConfig::level_name(level),
            category,
            message
        );
    }
    let detail = serde_json::json!({
        "level": logging::LogConfig::level_name(level),
        "category": category,
        "message": message,
    })
    .to_string();
    record_event(state, "log.created", category, Some(detail)).await;
}

async fn record_http_log(
    state: &AppState,
    request_id: &str,
    transaction: &logging::HttpTransactionLog,
) {
    let level = logging::response_level(transaction.response.status_code);
    let configured_level = *state.log_level.read().await;
    let log_config = logging::LogConfig {
        level: configured_level,
        log_requests: configured_level <= logging::LogLevel::Debug,
        log_responses: true,
        log_errors_only: false,
    };
    if !log_config.should_log(level) {
        return;
    }
    let detail = serde_json::json!({
        "level": logging::LogConfig::level_name(level),
        "category": "http",
        "message": logging::transaction_summary(transaction),
        "request_id": request_id,
        "method": transaction.request.method,
        "path": logging::redacted_path(&transaction.request.path),
        "status": transaction.response.status_code,
        "duration_ms": transaction.response.duration_ms,
        "remote_addr": transaction.request.remote_addr,
    })
    .to_string();
    record_event(state, "log.created", "http", Some(detail)).await;
}

async fn persist_event_record_checked(
    state: &AppState,
    record: &EventRecord,
) -> Result<bool, String> {
    let Some(db) = state.db.as_ref() else {
        return Ok(false);
    };
    let persisted = crate::persistence::EventRecord {
        id: i64::try_from(record.id).unwrap_or(i64::MAX),
        kind: record.kind.clone(),
        resource: record.resource.clone(),
        detail: record.detail.clone(),
        created_at: i64::try_from(record.created_at).unwrap_or(i64::MAX),
    };
    db.insert_event_and_prune(&persisted, EVENT_HISTORY_LIMIT as i32)
        .await
        .map_err(|error| format!("event persistence failed: {error}"))?;
    Ok(true)
}

